import re

def analyze_job_description(job_description: str):
    """Analyzes the job description text and extracts required skills, responsibilities, and criteria sections.
    Returns a dictionary with three keys: 'skills', 'responsibilities', and 'criteria', each containing a list of strings.
    """
    # Define section headings and regex patterns
    section_patterns = {
        'skills': r'(?:required skills|skills required|skills|technical skills):?\\s*(.*?)(?=\\n{2,}|\Z)',
        'responsibilities': r'(?:responsibilities|key responsibilities|job duties):?\\s*(.*?)(?=\\n{2,}|\Z)',
        'criteria': r'(?:requirements|qualifications|criteria|experience needed):?\\s*(.*?)(?=\\n{2,}|\Z)'
    }
    results = {'skills': [], 'responsibilities': [], 'criteria': []}

    # Normalize whitespace
    text = job_description + '\\n\\n'

    for section, pattern in section_patterns.items():
        match = re.search(pattern, text, re.IGNORECASE | re.DOTALL)
        if match:
            block = match.group(1).strip()
            # Split by lines or common delimiters
            lines = re.split(r'[\\n•\\-]+', block)
            for item in lines:
                item = item.strip(' :;,.').replace("*", "")
                if item:
                    results[section].append(item)

    # Fallback keyword-based extraction if sections are sparse or not found, focusing on skills
    if not results['skills']:
        keywords = ['Python', 'Java', 'communication', 'SQL', 'AWS', 'JavaScript', 'C++', 'C#', 'React', 'Angular', 'Node.js', 'Data Analysis', 'Machine Learning', 'Deep Learning', 'Cloud Computing', 'Project Management', 'Testing', 'DevOps'] # Expanded keyword list
        for kw in keywords:
            if re.search(r'\\b' + re.escape(kw) + r'\\b', text, re.IGNORECASE):
                results['skills'].append(kw)

    return results['skills'], results['responsibilities'], results['criteria']
